            while (tok && ix < MAX_BLOCKS) {
                spec->perm[ix++] = atoi(tok);
                tok = strtok(NULL, " ");
            }
        } else if (strncmp(line, "block ", 6) == 0) {
            BlockEntry *be = &spec->blocks[spec->block_count++];
            char *tok = strtok(line + 6, " ");
            be->rb = atoi(tok);
            tok = strtok(NULL, " ");
            be->cb = atoi(tok);
            for (int k = 0; k < spec->bs * spec->bs; k++) {
                tok = strtok(NULL, " ");
                be->vals[k] = tok ? atof(tok) : 0.0;
            }
